package analyzer

import (
	"go/ast"
	"go/parser"
	"go/token"
	"os"
	"path/filepath"
	"strings"
)

// Scanner Ńü»ŃâćŃé╣ŃâłŃâĽŃéíŃéĄŃâźŃéĺŔÁ░Šč╗ŃüŚŃüŽŃé╣ŃâíŃâźŃéĺŠĄťňç║ŃüÖŃéőŃÇé
type Scanner struct {
	Detectors      []Detector
	EnabledSmells  map[SmellType]bool
	DisabledSmells map[SmellType]bool
}

// NewScanner Ńü»ŃâçŃâĽŃéęŃâźŃâłŔĘşň«ÜŃü«ScannerŃéĺšöčŠłÉŃüÖŃéőŃÇé
func NewScanner() *Scanner {
	return &Scanner{
		Detectors: AllDetectors(),
	}
}

// ScanDir Ńü»ŃâçŃéúŃâČŃé»ŃâłŃâ¬ÚůŹńŞőŃü« _test.go ŃâĽŃéíŃéĄŃâźŃéĺňćŹňŞ░šÜäŃüźŃé╣ŃéşŃâúŃâ│ŃüÖŃéőŃÇé
func (s *Scanner) ScanDir(dir string) ([]TestSmell, error) {
	var allSmells []TestSmell
	err := filepath.Walk(dir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.IsDir() {
			base := filepath.Base(path)
			if base == "vendor" || strings.HasPrefix(base, ".") {
				return filepath.SkipDir
			}
			return nil
		}
		if !strings.HasSuffix(path, "_test.go") {
			return nil
		}
		smells, err := s.ScanFile(path)
		if err != nil {
			return nil // ŃâĹŃâ╝Ńé╣ŃéĘŃâęŃâ╝Ńü»šäíŔŽľŃüŚŃüŽšÂÜŔíî
		}
		allSmells = append(allSmells, smells...)
		return nil
	})
	return allSmells, err
}

// ScanFile Ńü»ňŹśńŞÇŃü«ŃâćŃé╣ŃâłŃâĽŃéíŃéĄŃâźŃéĺŃé╣ŃéşŃâúŃâ│ŃüÖŃéőŃÇé
func (s *Scanner) ScanFile(path string) ([]TestSmell, error) {
	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, path, nil, parser.ParseComments)
	if err != nil {
		return nil, err
	}
	return s.scanAST(fset, file), nil
}

// ScanSource Ńü»ŃéŻŃâ╝Ńé╣Ńé│Ńâ╝ŃâëŠľçňşŚňłŚŃéĺŃé╣ŃéşŃâúŃâ│ŃüÖŃéő´╝łŃâćŃé╣ŃâłšöĘ´╝ëŃÇé
func (s *Scanner) ScanSource(src string) ([]TestSmell, error) {
	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, "test_test.go", src, parser.ParseComments)
	if err != nil {
		return nil, err
	}
	return s.scanAST(fset, file), nil
}

func (s *Scanner) scanAST(fset *token.FileSet, file *ast.File) []TestSmell {
	var smells []TestSmell
	for _, decl := range file.Decls {
		fn, ok := decl.(*ast.FuncDecl)
		if !ok {
			continue
		}
		for _, detector := range s.Detectors {
			if !s.isEnabled(detector.Type()) {
				continue
			}
			smells = append(smells, detector.Detect(fset, file, fn)...)
		}
	}
	return smells
}

func (s *Scanner) isEnabled(t SmellType) bool {
	if len(s.EnabledSmells) > 0 {
		return s.EnabledSmells[t]
	}
	if len(s.DisabledSmells) > 0 {
		return !s.DisabledSmells[t]
	}
	return true
}

package analyzer

// AllDetectors Ńü»ňůĘŠĄťňç║ňÖĘŃéĺŔ┐öŃüÖŃÇé
func AllDetectors() []Detector {
	return []Detector{
		&EmptyTestDetector{},
		&MissingAssertionDetector{},
		&SleepyTestDetector{},
		&RedundantPrintDetector{},
		&ConditionalTestLogicDetector{},
		&MagicNumberTestDetector{},
		&MissingErrorCheckDetector{},
		&MissingHelperDetector{},
	}
}

package analyzer

import "fmt"

// SmellType Ńü»ŃâćŃé╣ŃâłŃé╣ŃâíŃâźŃü«šĘ«Úí×ŃéĺŔíĘŃüÖŃÇé
type SmellType string

const (
	SmellEmptyTest            SmellType = "EMPTY_TEST"
	SmellMissingAssertion     SmellType = "MISSING_ASSERTION"
	SmellSleepyTest           SmellType = "SLEEPY_TEST"
	SmellRedundantPrint       SmellType = "REDUNDANT_PRINT"
	SmellConditionalTestLogic SmellType = "CONDITIONAL_TEST_LOGIC"
	SmellMagicNumberTest      SmellType = "MAGIC_NUMBER_TEST"
	SmellMissingErrorCheck    SmellType = "MISSING_ERROR_CHECK"
	SmellMissingHelper        SmellType = "MISSING_HELPER"
)

// SmellDisplayName Ńü»Ńé╣ŃâíŃâźŃü«ŔíĘšĄ║ňÉŹŃéĺŔ┐öŃüÖŃÇé
var SmellDisplayName = map[SmellType]string{
	SmellEmptyTest:            "Empty Test",
	SmellMissingAssertion:     "Missing Assertion",
	SmellSleepyTest:           "Sleepy Test",
	SmellRedundantPrint:       "Redundant Print",
	SmellConditionalTestLogic: "Conditional Test Logic",
	SmellMagicNumberTest:      "Magic Number Test",
	SmellMissingErrorCheck:    "Missing Error Check",
	SmellMissingHelper:        "Missing t.Helper()",
}

// SmellMessage Ńü»Ńé╣ŃâíŃâźŠĄťňç║ŠÖéŃü«ŃâęŃéĄŃé¬Ńâ│Ńü«ŃâíŃââŃé╗Ńâ╝ŃéŞŃéĺŔ┐öŃüÖŃÇé
var SmellMessage = map[SmellType]string{
	SmellEmptyTest:            "šę║Ńü«ŃâćŃé╣ŃâłŃüĘŃüőŃüŐňëŹŃüŁŃéî@t_wadaŃü«ňëŹŃüžŃééňÉîŃüśń║őŔĘÇŃüłŃéôŃü«´╝č",
	SmellMissingAssertion:     "ŃéóŃéÁŃâ╝ŃéĚŃâžŃâ│Ńü«Ńü¬ŃüäŃâćŃé╣ŃâłŃüĘŃüőŃüŐňëŹŃüŁŃéî@t_wadaŃü«ňëŹŃüžŃééňÉîŃüśń║őŔĘÇŃüłŃéôŃü«´╝č",
	SmellSleepyTest:           "ŃâćŃé╣ŃâłŃüžsleepŃüĘŃüőŃüŐňëŹŃüŁŃéî@t_wadaŃü«ňëŹŃüžŃééňÉîŃüśń║őŔĘÇŃüłŃéôŃü«´╝č",
	SmellRedundantPrint:       "ŃâćŃé╣ŃâłŃüžfmt.PrintlnŃüĘŃüőŃüŐňëŹŃüŁŃéî@t_wadaŃü«ňëŹŃüžŃééňÉîŃüśń║őŔĘÇŃüłŃéôŃü«´╝č",
	SmellConditionalTestLogic: "ŃâćŃé╣ŃâłŃüžŠŁíń╗Âňłćň▓ÉŃüĘŃüőŃüŐňëŹŃüŁŃéî@t_wadaŃü«ňëŹŃüžŃééňÉîŃüśń║őŔĘÇŃüłŃéôŃü«´╝č",
	SmellMagicNumberTest:      "ŃâćŃé╣ŃâłŃüžŃâ×ŃéŞŃââŃé»ŃâŐŃâ│ŃâÉŃâ╝ŃüĘŃüőŃüŐňëŹŃüŁŃéî@t_wadaŃü«ňëŹŃüžŃééňÉîŃüśń║őŔĘÇŃüłŃéôŃü«´╝č",
	SmellMissingErrorCheck:    "errorŃéĺšäíŔŽľŃüÖŃéőŃâćŃé╣ŃâłŃüĘŃüőŃüŐňëŹŃüŁŃéî@t_wadaŃü«ňëŹŃüžŃééňÉîŃüśń║őŔĘÇŃüłŃéôŃü«´╝č",
	SmellMissingHelper:        "t.Helper()ŃéĺŠŤŞŃüőŃü¬ŃüäŃâśŃâźŃâĹŃâ╝ŃüĘŃüőŃüŐňëŹŃüŁŃéî@t_wadaŃü«ňëŹŃüžŃééňÉîŃüśń║őŔĘÇŃüłŃéôŃü«´╝č",
}

// TestSmell Ńü»ŠĄťňç║ŃüĽŃéîŃüčŃâćŃé╣ŃâłŃé╣ŃâíŃâźŃéĺŔíĘŃüÖŃÇé
type TestSmell struct {
	Type     SmellType
	File     string
	FuncName string
	Line     int
	Message  string
}

func (s TestSmell) String() string {
	return fmt.Sprintf("[%s] %s:%d in %s() - %s", s.Type, s.File, s.Line, s.FuncName, s.Message)
}

// AllSmellTypes Ńü»ňůĘŃé╣ŃâíŃâźŃé┐ŃéĄŃâŚŃéĺŔ┐öŃüÖŃÇé
func AllSmellTypes() []SmellType {
