package main

import (
	"flag"
	"fmt"
	"os"
	"strings"

	"github.com/135yshr/savanna/analyzer"
	"github.com/135yshr/savanna/reporter"
)

var (
	version = "0.1.0"
)

func main() {
	var (
		reportFormat string
		outputDir    string
		failOnSmell  bool
		enabledStr   string
		disabledStr  string
		showVersion  bool
		listSmells   bool
	)

	flag.StringVar(&reportFormat, "format", "console", "ŃâČŃâŁŃâ╝ŃâłňŻóň╝Ć (console, json)")
	flag.StringVar(&outputDir, "output", "savanna-reports", "ŃâČŃâŁŃâ╝Ńâłňç║ňŐŤŃâçŃéúŃâČŃé»ŃâłŃâ¬ (jsonšöĘ)")
	flag.BoolVar(&failOnSmell, "fail", false, "Ńé╣ŃâíŃâźŠĄťňç║ŠÖéŃüźšÁéń║ćŃé│Ńâ╝Ńâë1ŃüžšÁéń║ć")
	flag.StringVar(&enabledStr, "enable", "", "ŠťëňŐ╣ŃüźŃüÖŃéőŃé╣ŃâíŃâź (ŃéźŃâ│Ńâ×ňî║ňłçŃéŐ)")
	flag.StringVar(&disabledStr, "disable", "", "šäíňŐ╣ŃüźŃüÖŃéőŃé╣ŃâíŃâź (ŃéźŃâ│Ńâ×ňî║ňłçŃéŐ)")
	flag.BoolVar(&showVersion, "version", false, "ŃâÉŃâ╝ŃéŞŃâžŃâ│ŃéĺŔíĘšĄ║")
	flag.BoolVar(&listSmells, "list", false, "ŠĄťňç║ňĆ»ŔâŻŃü¬Ńé╣ŃâíŃâźńŞÇŔŽžŃéĺŔíĘšĄ║")
	flag.Parse()

	if showVersion {
		fmt.Printf("savanna %s\n", version)
		return
	}

	if listSmells {
		fmt.Println("ŠĄťňç║ňĆ»ŔâŻŃü¬ŃâćŃé╣ŃâłŃé╣ŃâíŃâź:")
		for _, t := range analyzer.AllSmellTypes() {
			fmt.Printf("  %-30s %s\n", t, analyzer.SmellDisplayName[t])
		}
		return
	}

	dirs := flag.Args()
	if len(dirs) == 0 {
		dirs = []string{"."}
	}

	scanner := analyzer.NewScanner()

	if enabledStr != "" {
		scanner.EnabledSmells = parseSmellList(enabledStr)
	}
	if disabledStr != "" {
		scanner.DisabledSmells = parseSmellList(disabledStr)
	}

	var allSmells []analyzer.TestSmell
	for _, dir := range dirs {
		smells, err := scanner.ScanDir(dir)
		if err != nil {
			fmt.Fprintf(os.Stderr, "ŃéĘŃâęŃâ╝: %s Ńü«Ńé╣ŃéşŃâúŃâ│ŃüźňĄ▒ŠĽŚ: %v\n", dir, err)
			os.Exit(1)
		}
		allSmells = append(allSmells, smells...)
	}

	var rep reporter.Reporter
	switch reportFormat {
	case "json":
		rep = &reporter.JSONReporter{OutputDir: outputDir}
	default:
		rep = reporter.NewConsoleReporter()
	}

	if err := rep.Report(allSmells); err != nil {
		fmt.Fprintf(os.Stderr, "ŃâČŃâŁŃâ╝Ńâłňç║ňŐŤŃéĘŃâęŃâ╝: %v\n", err)
		os.Exit(1)
	}

	if failOnSmell && len(allSmells) > 0 {
		os.Exit(1)
	}
}

func parseSmellList(s string) map[analyzer.SmellType]bool {
	m := make(map[analyzer.SmellType]bool)
	for _, name := range strings.Split(s, ",") {
		name = strings.TrimSpace(strings.ToUpper(name))
		if name != "" {
			m[analyzer.SmellType(name)] = true
		}
	}
	return m
}

package reporter

import "github.com/135yshr/savanna/analyzer"

// Reporter Ńü»Ńé╣ŃâíŃâźŃâČŃâŁŃâ╝ŃâłŃéĺňç║ňŐŤŃüÖŃéőŃéĄŃâ│Ńé┐Ńâ╝ŃâĽŃéžŃâ╝Ńé╣ŃÇé
type Reporter interface {
	Report(smells []analyzer.TestSmell) error
}

